    {
        'name': 'litellm',
        'base_url': 'http://localhost:4000/v1',
        'models': {
            'groq-llama': {
                'context_length': 8192,
            },
            'groq-qwen': {
                'context_length': 32768,
            },
            'groq-deepseek': {
                'context_length': 32768,
            }
        }
    }
]

# Set auxiliary tasks to use free Groq models via LiteLLM
# Note: Groq has NO vision, so keep vision + compression on DeepSeek
aux = c.setdefault('auxiliary', {})
for key in aux:
    if isinstance(aux[key], dict):
        if key in ('vision',):
            # Keep vision on DeepSeek (Groq has no vision)
            aux[key]['provider'] = 'custom:litellm'
            aux[key]['model'] = 'groq-llama'
        else:
            # Everything else -> free Groq via LiteLLM
            aux[key]['provider'] = 'custom:litellm'
            aux[key]['model'] = 'groq-llama'

# Set LiteLLM API key in provider config
c['providers']['litellm'] = c.get('providers', {}).get('litellm', {})
c['providers']['litellm']['api_key'] = 'sk-hermes-litellm-sunstein-2026'
c['providers']['litellm']['base_url'] = 'http://localhost:4000/v1'

# Add LiteLLM to credential pool
auth = json.load(open('/root/.hermes/auth.json'))
auth.setdefault('credential_pool', {})
auth['credential_pool']['custom:litellm'] = [{
    'api_key': 'sk-hermes-litellm-sunstein-2026',
    'exhausted': False,
    'status': 'active'
}]
json.dump(auth, open('/root/.hermes/auth.json', 'w'), indent=2)

with open('/root/.hermes/config.yaml', 'w') as f:
